// Construye el Set de IDs Zendesk abiertos
const tickets = $input.all().map(i => i.json).filter(Boolean);
const zdIds = new Set(tickets.map(t => String(t.id)).filter(Boolean));
return [{ json: { _zd_open_ids: [...zdIds], _zd_open_total: zdIds.size } }];

// 1) Solo tareas COMPLETADAS en los ÚLTIMOS 180 DÍAS (reduce volumen)
// 2) Intenta extraer zendesk_id desde NAME o HTML_NOTES (sin HTTP extra)
// 3) Las que no se puedan resolver así pasan por separado a fetch attachments
const tasks = $input.all().map(i => i.json).filter(Boolean);
const cutoff = Date.now() - 180 * 86400000;

function findZdId(s) {
  if (!s) return null;
  const m = String(s).match(/#\s*(\d{2,7})/);
  return m ? m[1] : null;
}

const withId = [];     // tareas con zendesk_id ya extraído
const needAtt = [];    // necesitan HTTP a attachments
for (const t of tasks) {
  if (!t || t.completed !== true) continue;
  if (!t.completed_at || new Date(t.completed_at).getTime() < cutoff) continue;
  const zdId = findZdId(t.name) || findZdId(t.html_notes);
  if (zdId) {
    withId.push({ ...t, _zd_id: zdId, _src: 'name_or_notes' });
  } else {
    needAtt.push({ ...t });
  }
}
return [
  ...withId.map(t => ({ json: t })),
  ...needAtt.map(t => ({ json: t }))
];

// Cruza Asana completadas (con zendesk_id resuelto vía name/notes o
// attachments) contra los IDs Zendesk abiertos. Detecta desincronizaciones.
const tasks = $('Solo Completadas (180d) + Pre-extract').all().map(i => i.json);
const attResults = $input.all().map(i => i.json);
const zdData = $('Save ZD Open').first().json;
const zdOpenIds = new Set((zdData._zd_open_ids || []).map(String));

const mismatches = [];
const noMatch = [];
const zdMatched = new Set();
let srcName = 0, srcAtt = 0;

for (let i = 0; i < tasks.length; i++) {
  const task = tasks[i];
  let zdId = task._zd_id || null;
  if (zdId) {
    srcName++;
  } else {
    // Caer al attachment correspondiente por índice
    const attResp = attResults[i] || {};
    const atts = Array.isArray(attResp.data) ? attResp.data : [];
    for (const att of atts) {
      const name = att && att.name ? String(att.name) : '';
      const m = name.match(/#\s*(\d{2,7})/);
      if (m) { zdId = m[1]; srcAtt++; break; }
    }
  }

  if (!zdId) {
    noMatch.push({
      asana_gid: task.gid, asana_name: task.name,
      asana_url: task.permalink_url,
      asana_completed_at: task.completed_at
    });
    continue;
  }

  if (zdOpenIds.has(String(zdId))) {
    mismatches.push({
      zendesk_id: parseInt(zdId, 10),
      zendesk_url: `https://soporteyurest.zendesk.com/agent/tickets/${zdId}`,
      asana_gid: task.gid,
      asana_name: task.name,
      asana_url: task.permalink_url,
      asana_completed_at: task.completed_at,
      _source: task._zd_id ? 'name_or_notes' : 'attachment'
    });
    zdMatched.add(String(zdId));
  }
}

const zdOpenNotInAsanaCompleted = [...zdOpenIds].filter(id => !zdMatched.has(id));

return [{ json: {
  generated_at: new Date().toISOString(),
  zendesk_open_total: zdOpenIds.size,
  asana_completed_180d_total: tasks.length,
  resolved_from_name_notes: srcName,
  resolved_from_attachments: srcAtt,
  mismatches_total: mismatches.length,
  mismatches_ids_csv: mismatches.map(m => m.zendesk_id).join(','),
  mismatches: mismatches.sort((a,b) => (b.asana_completed_at || '').localeCompare(a.asana_completed_at || '')),
  asana_completed_sin_ticket_legible: noMatch,
  zendesk_abiertos_sin_asana_completada: zdOpenNotInAsanaCompleted
} }];
